const rows = [];
for (const key of Object.keys(DATA)) {
  const [subject, topic] = key.split("__");
  for (const q of DATA[key]) {
    rows.push({
      "Предмет": subject,
      "Тема": topic,
      "Текст вопроса": q[0],
      "Вариант A": q[1],
      "Вариант B": q[2],
      "Вариант C": q[3],
      "Вариант D": q[4],
      "Правильный ответ (a/b/c/d)": q[5],
      "Сложность": q[6],
      "Объяснение (необязательно)": q[7] || "",
    });
  }
}

const wb = XLSX.utils.book_new();
try {
  const starter = XLSX.readFile("UniPrep_question_bank_starter.xlsx");
  if (starter.Sheets["Инструкция"])
    XLSX.utils.book_append_sheet(wb, starter.Sheets["Инструкция"], "Инструкция");
} catch(_) {}

XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(SUBJECTS),    "Предметы");
XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(TOPICS_META), "Темы");
XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(rows),        "Вопросы");
XLSX.writeFile(wb, "question_bank_full.xlsx");

const counts = {};
for (const k of Object.keys(DATA)) counts[k] = DATA[k].length;
console.log("✅  Saved: question_bank_full.xlsx");
console.log("   Questions per topic:");
for (const [k,n] of Object.entries(counts)) console.log(`     ${k}: ${n}`);
console.log(`   Total: ${rows.length} questions`);
